import React, { useCallback, useEffect, useState } from 'react'
import {
  Button,
  Card,
  Col,
  Divider,
  Drawer,
  message,
  Row,
  Spin,
  Typography,
  Tag,
} from 'antd'
import {
  DownloadOutlined,
  SettingOutlined,
  AppstoreOutlined,
  CheckCircleOutlined,
  SwapOutlined,
} from '@ant-design/icons'
import service from '@/utils/api'
import useLocale from '@/hooks/useLocale'
import ThemeConfigPanel from './components/ThemeConfigPanel'
import styles from './style.module.less'

const { Title, Text } = Typography

interface BuiltinTheme {
  id: string
  name: string
  description: string
  author: string
  themeDir: string
}

interface ThemeStatus {
  installed: boolean
  isCurrent?: boolean
}

interface InstalledThemeInfo {
  themeDir: string
  name: string
  id: string
  isBuiltin: boolean
  isCurrent: boolean
}

const ThemeMarketPage: React.FC = () => {
  const t = useLocale()
  const [themes, setThemes] = useState<BuiltinTheme[]>([])
  const [statusMap, setStatusMap] = useState<Record<string, ThemeStatus>>({})
  const [installedThemes, setInstalledThemes] = useState<InstalledThemeInfo[]>([])
  const [currentTheme, setCurrentTheme] = useState<string>('')
  const [loading, setLoading] = useState(true)
  const [installing, setInstalling] = useState<string | null>(null)
  const [switching, setSwitching] = useState<string | null>(null)
  const [configModal, setConfigModal] = useState<{
    visible: boolean
    themeId: string
    themeName: string
  }>({ visible: false, themeId: '', themeName: '' })

  const fetchThemes = useCallback(async () => {
    try {
      const res = await service.get('/hexopro/api/theme/list')
      setThemes(res.data || [])
    } catch (err) {
      message.error(t['theme.list.fetchFailed'] || '获取主题列表失败')
    }
  }, [t])

  // 获取所有已安装主题（包括非内置主题）
  const fetchInstalledThemes = useCallback(async () => {
    try {
      const res = await service.get('/hexopro/api/theme/installed-all')
      if (res.data) {
        setInstalledThemes(res.data.themes || [])
        setCurrentTheme(res.data.currentTheme || '')

        // 更新内置主题的状态
        const map: Record<string, ThemeStatus> = {}
        res.data.themes.forEach((theme: InstalledThemeInfo) => {
          const builtinTheme = themes.find((t) => t.themeDir === theme.themeDir)
          if (builtinTheme) {
            map[builtinTheme.id] = {
              installed: true,
              isCurrent: theme.isCurrent,
            }
          }
        })
        // 对于未安装的内置主题，设置状态为未安装
        themes.forEach((theme) => {
          if (!map[theme.id]) {
            map[theme.id] = { installed: false, isCurrent: false }
          }
        })
        setStatusMap(map)
      }
    } catch {
      // 如果新接口失败，回退到旧接口
      await fetchInstalledStatusLegacy()
    }
  }, [themes])

  // 旧版接口回退
  const fetchInstalledStatusLegacy = async () => {
    if (themes.length === 0) return
    const map: Record<string, ThemeStatus> = {}
    await Promise.all(
      themes.map(async (theme) => {
        try {
          const res = await service.get('/hexopro/api/theme/installed', {
            params: { themeId: theme.id },
          })
          map[theme.id] = res.data || { installed: false }
        } catch {
          map[theme.id] = { installed: false }
        }
      })
    )
    setStatusMap(map)
  }

  const fetchInstalledStatus = useCallback(async () => {
    await fetchInstalledThemes()
  }, [fetchInstalledThemes])

  useEffect(() => {
    const load = async () => {
      setLoading(true)
      await fetchThemes()
      setLoading(false)
    }
    void load()
  }, [fetchThemes])

  useEffect(() => {
    if (themes.length > 0) {
      void fetchInstalledStatus()
    }
  }, [themes, fetchInstalledStatus])

  const handleInstall = async (themeId: string) => {
    setInstalling(themeId)
    try {
      await service.post('/hexopro/api/theme/install', { themeId })
      message.success(t['theme.install.success'] || '主题安装完成')
      await fetchInstalledStatus()
    } catch {
      message.error(t['theme.install.failed'] || '安装失败')
    } finally {
      setInstalling(null)
    }
  }

  const handleSwitch = async (themeId: string) => {
    setSwitching(themeId)
    try {
      await service.post('/hexopro/api/theme/switch', { themeId })
      message.success(t['theme.switch.success'] || '主题切换成功')
      await fetchInstalledStatus()
    } catch {
      message.error(t['theme.switch.failed'] || '切换失败')
    } finally {
      setSwitching(null)
    }
  }

  const openConfig = (theme: BuiltinTheme) => {
    setConfigModal({
      visible: true,
      themeId: theme.id,
      themeName: theme.name,
    })
  }

  const closeConfig = () => {
    setConfigModal({
      visible: false,
      themeId: '',
      themeName: '',
    })
  }

  // 获取非内置的已安装主题
  const nonBuiltinInstalled = installedThemes.filter((t) => !t.isBuiltin)

  return (
    <div className={styles.container}>
      <Row gutter={[16, 16]}>
        <Col span={24}>
          <Title level={4}>
            <AppstoreOutlined style={{ marginRight: 8 }} />
            {t['theme.market.title'] || '主题市场'}
          </Title>
          <Text type="secondary">
            {t['theme.market.desc'] ||
              '一键安装 Hexo 主题，可视化配置主题参数'}
          </Text>
        </Col>
      </Row>

      <Divider />

      {currentTheme && (
        <>
          <Row gutter={[16, 16]} style={{ marginBottom: 16 }}>
            <Col span={24}>
              <Text type="secondary">
                {t['theme.current.using'] || '当前使用'}:{' '}
                <Tag color="blue" icon={<CheckCircleOutlined />}>
                  {installedThemes.find((t) => t.isCurrent)?.name || currentTheme}
                </Tag>
              </Text>
            </Col>
          </Row>
          <Divider />
        </>
      )}

      <Spin spinning={loading}>
        <div className={styles.themeGrid}>
          {themes.map((theme) => {
            const status = statusMap[theme.id] || { installed: false, isCurrent: false }
            const isInstalling = installing === theme.id
            const isSwitching = switching === theme.id

            return (
              <Card key={theme.id} className={styles.themeCard} hoverable>
                <div className={styles.themePreview}>
                  {theme.name}
                  {status.isCurrent && (
                    <div className={styles.currentBadge}>
                      <CheckCircleOutlined />
                    </div>
                  )}
                </div>
                <div className={styles.themeInfo}>
                  <div className={styles.themeName}>{theme.name}</div>
                  <div className={styles.themeDesc}>{theme.description}</div>
                  <div className={styles.themeAuthor}>
                    {t['theme.author'] || '作者'}: {theme.author}
                  </div>
                </div>
                <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
                  {!status.installed ? (
                    <Button
                      type="primary"
                      icon={<DownloadOutlined />}
                      loading={isInstalling}
                      onClick={() => handleInstall(theme.id)}
                    >
                      {t['theme.install'] || '一键安装'}
                    </Button>
                  ) : (
                    <>
                      {status.isCurrent ? (
                        <Button disabled type="primary">
                          <CheckCircleOutlined />
                          {t['theme.current'] || '当前使用'}
                        </Button>
                      ) : (
                        <Button
                          type="primary"
                          icon={<SwapOutlined />}
                          loading={isSwitching}
                          onClick={() => handleSwitch(theme.id)}
                        >
                          {t['theme.switch'] || '切换'}
                        </Button>
                      )}
                      <Button
                        icon={<SettingOutlined />}
                        onClick={() => openConfig(theme)}
                      >
                        {t['theme.config'] || '配置'}
                      </Button>
                    </>
                  )}
                </div>
              </Card>
            )
          })}
        </div>

        {/* 非内置已安装主题 */}
        {nonBuiltinInstalled.length > 0 && (
          <>
            <Divider />
            <Title level={5}>
              {t['theme.other.installed'] || '其他已安装主题'}
            </Title>
            <div className={styles.themeGrid} style={{ marginTop: 16 }}>
              {nonBuiltinInstalled.map((theme) => (
                <Card key={theme.themeDir} className={styles.themeCard} hoverable>
                  <div className={styles.themePreview}>{theme.name}</div>
                  <div className={styles.themeInfo}>
                    <div className={styles.themeName}>{theme.name}</div>
                    <div className={styles.themeDesc}>
                      {t['theme.nonbuiltin'] || '非市场主题'}
                    </div>
                    <div className={styles.themeAuthor}>
                      {t['theme.dir'] || '目录'}: {theme.themeDir}
                    </div>
                  </div>
                  <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
                    {theme.isCurrent ? (
                      <Button disabled type="primary">
                        <CheckCircleOutlined />
                        {t['theme.current'] || '当前使用'}
                      </Button>
                    ) : (
                      <Button
                        type="primary"
                        icon={<SwapOutlined />}
                        loading={switching === theme.themeDir}
                        onClick={() => handleSwitch(theme.themeDir)}
                      >
                        {t['theme.switch'] || '切换'}
                      </Button>
                    )}
                  </div>
                </Card>
              ))}
            </div>
          </>
        )}
      </Spin>

      <Drawer
        title={`${t['theme.config'] || '配置'} - ${configModal.themeName}`}
        placement="right"
        onClose={closeConfig}
        open={configModal.visible}
        width={700}
        destroyOnClose
        bodyStyle={{ padding: 0 }}
      >
        {configModal.visible && (
          <ThemeConfigPanel
            themeId={configModal.themeId}
            themeName={configModal.themeName}
            onClose={closeConfig}
          />
        )}
      </Drawer>
    </div>
  )
}

export default ThemeMarketPage
